/**
 * Realiza una rotación a la derecha de un nodo.
 * @param node un nodo a rotar
 * @return un nuevo padre del {@code node}
 */
private TreeNode<T> rotateRight(TreeNode<T> node) {
    if (node == null || node.left == null) {
        // No se puede rotar
        return node;
    }
    // El nuevo padre será el hijo izquierdo
    TreeNode<T> newRoot = node.left;
    // El hijo derecho del nuevo padre se convierte en hijo izquierdo del nodo original
    node.left = newRoot.right;
    // El nodo original se convierte en el hijo derecho del nuevo padre
    newRoot.right = node;
    // Retorna el nuevo padre
    return newRoot;
}

