 * @param n el número de entrada
 * @return el factorial
 */
public static long factorial(int n) {
    if (n < 0) {
        throw new IllegalArgumentException("El número debe ser no negativo.");
    }
    long result = 1;
    for (int i = 2; i <= n; i++) {
        result *= i;
