/**
 * Elimina el {@code node} no nulo de la lista.
 */
private boolean unlink(ListNodeImpl<E> node) {
    if (node == null) {
        return false;
    }
    if (node.prev != null) {
        node.prev.next = node.next;
    } else {
        // node is head
        head = node.next;
    }
    if (node.next != null) {
        node.next.prev = node.prev;
    } else {
        // node is tail
        tail = node.prev;
    }
    node.next = null;
    node.prev = null;
    return true;
}

