/**
 * Decodifica octetos a caracteres utilizando la decodificación UTF-8 y agrega los caracteres a un StringBuffer.
 * @return el índice del siguiente carácter no verificado en la cadena para decodificar
 */
private static int decodeOctets(int i, ByteBuffer bb, StringBuilder sb) {
    while (i < bb.limit()) {
        // Get the byte and convert to unsigned
        int b = bb.get(i) & 0xFF;
        if ((b & 0x80) == 0) {
            // 1-byte character (ASCII)
            sb.append((char) b);
            i++;
        } else if ((b & 0xE0) == 0xC0) {
            // 2-byte character
            // Check for enough bytes
            if (i + 1 >= bb.limit())
                break;
            int b2 = bb.get(i + 1) & 0xFF;
            // Invalid continuation byte
            if ((b2 & 0xC0) != 0x80)
                break;
            sb.append((char) (((b & 0x1F) << 6) | (b2 & 0x3F)));
            i += 2;
        } else if ((b & 0xF0) == 0xE0) {
            // 3-byte character
            // Check for enough bytes
            if (i + 2 >= bb.limit())
                break;
            int b2 = bb.get(i + 1) & 0xFF;
            int b3 = bb.get(i + 2) & 0xFF;
            // Invalid continuation bytes
            if ((b2 & 0xC0) != 0x80 || (b3 & 0xC0) != 0x80)
                break;
            sb.append((char) (((b & 0x0F) << 12) | ((b2 & 0x3F) << 6) | (b3 & 0x3F)));
            i += 3;
        } else if ((b & 0xF8) == 0xF0) {
            // 4-byte character
            // Check for enough bytes
            if (i + 3 >= bb.limit())
                break;
            int b2 = bb.get(i + 1) & 0xFF;
